function renderIcons(root) {
  var el = root || document;
  var iconEls = el.querySelectorAll('[data-lucide]');
  iconEls.forEach(function (iconEl) {
    var name = iconEl.getAttribute('data-lucide');
    var paths = ICONS[name];
    if (!paths) return;
    var size = iconEl.getAttribute('width') || '18';
    var svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.setAttribute('xmlns', 'http://www.w3.org/2000/svg');
    svg.setAttribute('width', size);
    svg.setAttribute('height', size);
    svg.setAttribute('viewBox', '0 0 24 24');
    svg.setAttribute('fill', 'none');
    svg.setAttribute('stroke', 'currentColor');
    svg.setAttribute('stroke-width', '2');
    svg.setAttribute('stroke-linecap', 'round');
    svg.setAttribute('stroke-linejoin', 'round');
    svg.innerHTML = paths;
    if (iconEl.id) svg.setAttribute('id', iconEl.id);
    var classes = iconEl.className;
    if (classes) svg.setAttribute('class', classes);
    iconEl.parentNode.replaceChild(svg, iconEl);
  });
}

window.refreshIcons = renderIcons;

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', function () { renderIcons(); });
} else {
  renderIcons();
}

